1630 /// Try to convert "shuffle (binop), (binop)" into "binop (shuffle), (shuffle)".
1631 /// Try to convert "shuffle (cmpop), (cmpop)" into "cmpop (shuffle), (shuffle)".
1632 bool VectorCombine::foldShuffleOfBinops(Instruction &I) {
1633   ArrayRef<int> OldMask;
1634   Instruction *LHS, *RHS;
1635   if (!match(&I, m_Shuffle(m_OneUse(m_Instruction(LHS)),
1636                            m_OneUse(m_Instruction(RHS)), m_Mask(OldMask))))
1637     return false;
1638 
1639   // TODO: Add support for addlike etc.
1640   if (LHS->getOpcode() != RHS->getOpcode())
1641     return false;
1642 
1643   Value *X, *Y, *Z, *W;
1644   bool IsCommutative = false;
1645   CmpPredicate Pred = CmpInst::BAD_ICMP_PREDICATE;
1646   if (match(LHS, m_BinOp(m_Value(X), m_Value(Y))) &&
1647       match(RHS, m_BinOp(m_Value(Z), m_Value(W)))) {
1648     auto *BO = cast<BinaryOperator>(LHS);
1649     // Don't introduce poison into div/rem.
1650     if (llvm::is_contained(OldMask, PoisonMaskElem) && BO->isIntDivRem())
1651       return false;
1652     IsCommutative = BinaryOperator::isCommutative(BO->getOpcode());
1653   } else if (match(LHS, m_Cmp(Pred, m_Value(X), m_Value(Y))) &&
1654              match(RHS, m_SpecificCmp(Pred, m_Value(Z), m_Value(W)))) {
1655     IsCommutative = cast<CmpInst>(LHS)->isCommutative();
1656   } else
1657     return false;
1658 
1659   auto *ShuffleDstTy = dyn_cast<FixedVectorType>(I.getType());
1660   auto *BinResTy = dyn_cast<FixedVectorType>(LHS->getType());
1661   auto *BinOpTy = dyn_cast<FixedVectorType>(X->getType());
1662   if (!ShuffleDstTy || !BinResTy || !BinOpTy || X->getType() != Z->getType())
1663     return false;
1664 
1665   unsigned NumSrcElts = BinOpTy->getNumElements();
1666 
1667   // If we have something like "add X, Y" and "add Z, X", swap ops to match.
1668   if (IsCommutative && X != Z && Y != W && (X == W || Y == Z))
1669     std::swap(X, Y);
1670 
1671   auto ConvertToUnary = [NumSrcElts](int &M) {
1672     if (M >= (int)NumSrcElts)
1673       M -= NumSrcElts;
1674   };
1675 
1676   SmallVector<int> NewMask0(OldMask);
1677   TargetTransformInfo::ShuffleKind SK0 = TargetTransformInfo::SK_PermuteTwoSrc;
1678   if (X == Z) {
1679     llvm::for_each(NewMask0, ConvertToUnary);
1680     SK0 = TargetTransformInfo::SK_PermuteSingleSrc;
1681     Z = PoisonValue::get(BinOpTy);
1682   }
1683 
1684   SmallVector<int> NewMask1(OldMask);
1685   TargetTransformInfo::ShuffleKind SK1 = TargetTransformInfo::SK_PermuteTwoSrc;
1686   if (Y == W) {
1687     llvm::for_each(NewMask1, ConvertToUnary);
1688     SK1 = TargetTransformInfo::SK_PermuteSingleSrc;
1689     W = PoisonValue::get(BinOpTy);
1690   }
1691 
1692   // Try to replace a binop with a shuffle if the shuffle is not costly.
1693   InstructionCost OldCost =
1694       TTI.getInstructionCost(LHS, CostKind) +
1695       TTI.getInstructionCost(RHS, CostKind) +
1696       TTI.getShuffleCost(TargetTransformInfo::SK_PermuteTwoSrc, BinResTy,
1697                          OldMask, CostKind, 0, nullptr, {LHS, RHS}, &I);
1698 
1699   InstructionCost NewCost =
1700       TTI.getShuffleCost(SK0, BinOpTy, NewMask0, CostKind, 0, nullptr, {X, Z}) +
1701       TTI.getShuffleCost(SK1, BinOpTy, NewMask1, CostKind, 0, nullptr, {Y, W});
1702 
1703   if (Pred == CmpInst::BAD_ICMP_PREDICATE) {
1704     NewCost +=
1705         TTI.getArithmeticInstrCost(LHS->getOpcode(), ShuffleDstTy, CostKind);
1706   } else {
1707     auto *ShuffleCmpTy =
1708         FixedVectorType::get(BinOpTy->getElementType(), ShuffleDstTy);
1709     NewCost += TTI.getCmpSelInstrCost(LHS->getOpcode(), ShuffleCmpTy,
1710                                       ShuffleDstTy, Pred, CostKind);
1711   }
1712 
1713   LLVM_DEBUG(dbgs() << "Found a shuffle feeding two binops: " << I
1714                     << "\n  OldCost: " << OldCost << " vs NewCost: " << NewCost
1715                     << "\n");
1716   if (NewCost >= OldCost)
1717     return false;
1718 
1719   Value *Shuf0 = Builder.CreateShuffleVector(X, Z, NewMask0);
1720   Value *Shuf1 = Builder.CreateShuffleVector(Y, W, NewMask1);
1721   Value *NewBO = Pred == CmpInst::BAD_ICMP_PREDICATE
1722                      ? Builder.CreateBinOp(
1723                            cast<BinaryOperator>(LHS)->getOpcode(), Shuf0, Shuf1)
1724                      : Builder.CreateCmp(Pred, Shuf0, Shuf1);
1725 
1726   // Intersect flags from the old binops.
1727   if (auto *NewInst = dyn_cast<Instruction>(NewBO)) {
1728     NewInst->copyIRFlags(LHS);
1729     NewInst->andIRFlags(RHS);
1730   }
1731 
1732   Worklist.pushValue(Shuf0);
1733   Worklist.pushValue(Shuf1);
1734   replaceValue(I, *NewBO);
1735   return true;
1736 }
